/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesAgreement, NotifyName), FormControlEventType::Lookup)]
public static void NotifyName_OnLookup(FormControl sender, FormControlEventArgs e)
{
    if(curExt() == "O001")
    {
        Query query = new Query();
        QueryBuildDataSource queryBuildDataSource;

        SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(CustTable), sender);

        sysTableLookup.addLookupField(fieldNum(CustTable, AccountNum));
        sysTableLookup.addLookupField(fieldNum(CustTable, CustGroup));

        queryBuildDataSource = query.addDataSource(tableNum(CustTable));

        sysTableLookup.parmQuery(query);

        sysTableLookup.performFormLookup();
    }

}
